solution_code:
#include <iostream>
#include <iomanip>
#include <vector>

enum Planet { mercury, venus, earth, mars, jupiter, saturn, uranus, neptune, numPlanets };

int main()
{
    std::vector<double> au(numPlanets);
    au[mercury]  = 0.39;
    au[venus]    = 0.72;
    au[earth]    = 1.00;
    au[mars]     = 1.52;
    au[jupiter]  = 5.20;
    au[saturn]   = 9.58;
    au[uranus]   = 19.22;
    au[neptune]  = 30.05;

    int n{};
    std::cin >> n;

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Distance: " << au[n] << " AU\n";

    return 0;
}

